-- {"operators": "OUTER_JOIN,AGGREGATE,FILTER,ORDER,LIMIT,HAVING", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "WAREHOUSE,DISTRICT,CUSTOMER,OORDER,ORDER_LINE"}
SELECT w.W_ID, d.D_ID, c.C_ID, COUNT(o.O_ID) as order_cnt, SUM(ol.OL_AMOUNT) as line_amount FROM WAREHOUSE w JOIN DISTRICT d ON w.W_ID = d.D_W_ID JOIN CUSTOMER c ON d.D_W_ID = c.C_W_ID AND d.D_ID = c.C_D_ID LEFT JOIN OORDER o ON c.C_ID = o.O_C_ID LEFT JOIN ORDER_LINE ol ON o.O_ID = ol.OL_O_ID WHERE w.W_TAX > 0.00 AND c.C_BALANCE < -500 GROUP BY w.W_ID, d.D_ID, c.C_ID HAVING COUNT(o.O_ID) > 1 ORDER BY w.W_ID, order_cnt DESC LIMIT 15;
